--cols-1: repeat(1, calc(100% / 1)); --cols-2: repeat(2, calc(100% / 2)); --cols-3: repeat(3, calc(100% / 3)); --cols-4: repeat(4, calc(100% / 4)); --cols-5: repeat(5, calc(100% / 5)); --cols-6: repeat(6, calc(100% / 6)); --cols-7: repeat(7, calc(100% / 7)); --cols-8: repeat(8, calc(100% / 8)); --cols-9: repeat(9, calc(100% / 9)); --cols-10: repeat(10, calc(100% / 10)); --cols-11: repeat(11, calc(100% / 11)); --cols-12: repeat(12, calc(100% / 12));
