/*------------------------- start dark-mode -------------------------*/ body.dark-mode,.dark-mode .label-input,.dark-mode .card:hover,body.dark-mode:not(.home-page) .search-wraper:is(.active),body.dark-mode:not(.home-page) .search-wraper:is(.active) .label-input{background-color:#121212!important}.dark-mode .widget-body,.dark-mode .footer-site,.dark-mode .sidebar-site .widget-content,.dark-mode .label-link,.dark-mode .toasts{background-color:#1c1c1c!important}.dark-mode .topbar .btn-icon,.dark-mode .icon-bar .icon{background-color:#3b3a3a!important;color:#fff!important}.dark-mode .menu-categories .menu-item-link{border-bottom-color:#3b3a3a!important}.dark-mode .card,.dark-mode .cover,.dark-mode .post-body,.dark-mode .post-body .official-accounts,.dark-mode .topbar,.dark-mode .menu-categories-wrap{background-color:#2b2b2b!important}.dark-mode .post-body .official-accounts{border-block-color:#121212!important}.dark-mode .card,.dark-mode .official-accounts-link,.dark-mode .topbar{box-shadow:var(--box-shadow-dark)!important}body.dark-mode,.dark-mode .card-website-text,.dark-mode .short-blog-description,.dark-mode .control-form,.dark-mode .nav-breadcrumb,.dark-mode .breadcrumb-item>*,.dark-mode .card:hover .card-website-text,.dark-mode .footer-links a:hover,.dark-mode .menu-categories .menu-item .menu-item-link{color:#e6e8f3!important}.dark-mode .website-single-title{text-shadow:1px 7px 6px rgb(0 0 0 / 30%)!important;color:#fff!important}.dark-mode .excerpt{color:#d5d5d5!important}.dark-mode .label-link{border-bottom-color:#2b2b2b!important;color:#e6e8f3!important}.dark-mode .footer-links a{color:#a4a4a4!important}.dark-mode .copy-right{color:#a4a4a4!important;border-top:1px dashed #323232!important}.dark-mode .cover .logo{box-shadow:var(--box-shadow-dark)!important}.dark-mode .widget-text{color:#85c2ff!important;border-bottom-color:#85c2ff!important}.dark-mode .widget-text:after{border-color:#85c2ff!important}.dark-mode .control-form{border-color:#3b3a3a!important}.dark-mode .post-meta-items{color:#c2cddb!important}.dark-mode .copy-right-wrap .link{color:#0d71f2!important}.dark-mode .toasts{border:1px solid #3e4042}.dark-mode .toast-topbar{border-bottom:1px solid #3e4042}.dark-mode #toc-body{background-color:#262626;!important}.dark-mode .toc-list .item-link{color:#c2cddb!important}@media(max-width:575px){.dark-mode .icon-bar{background-color:#2b2b2b!important}} /*------------------------- end dark-mode -------------------------*/
