];


function parseDateSafely(dateInput){if(dateInput instanceof Date&&!isNaN(dateInput))return dateInput;let d=new Date(dateInput);if(!isNaN(d.getTime()))return d;const rfcMatch=String(dateInput).match(/^(\w{3}), (\d{1,2}) (\w{3}) (\d{4}) (\d{2}):(\d{2}):(\d{2}) (?:GMT|UTC)$/);if(rfcMatch){const months={Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};const month=months[rfcMatch[3]];if(month!==undefined){d=new Date(parseInt(rfcMatch[4]),month,parseInt(rfcMatch[2]),parseInt(rfcMatch[5]),parseInt(rfcMatch[6]),parseInt(rfcMatch[7]));if(!isNaN(d.getTime()))return d}}return new Date()}function getLang(){if(lang){return lang.startsWith("ar")?"ar":"en"}return document.dir==="rtl"?"ar":"en"}function fun_convert_time(dateInput){const lang=getLang();const now=new Date();const past=parseDateSafely(dateInput);let diffSeconds=Math.floor((now-past)/1000);const text={ar:{ago:"منذ",now:"لحظة"},en:{ago:"ago",now:"just now"}};if(diffSeconds<0){return formatAgo(Math.abs(diffSeconds),lang)}if(diffSeconds<1){return lang==="ar"?` منذ ${text.ar.now}`:text.en.now}const intervals=[{label:"year",seconds:31536000},{label:"month",seconds:2592000},{label:"day",seconds:86400},{label:"hour",seconds:3600},{label:"minute",seconds:60},{label:"second",seconds:1},];for(const interval of intervals){const count=Math.floor(diffSeconds/interval.seconds);if(count>=1){const formatted=formatNumberWithUnit(count,interval.label,lang);return lang==="ar"?` منذ ${formatted}`:`${formatted}ago`}}return lang==="ar"?` منذ ${text.ar.now}`:text.en.now}function formatNumberWithUnit(value,unit,lang){const forms={ar:{second:{one:"ثانية واحدة",two:"ثانيتين",many:"ثوانٍ",single:"ثانية"},minute:{one:"دقيقة واحدة",two:"دقيقتين",many:"دقائق",single:"دقيقة"},hour:{one:"ساعة واحدة",two:"ساعتين",many:"ساعات",single:"ساعة"},day:{one:"يوم واحد",two:"يومين",many:"أيام",single:"يوم"},month:{one:"شهر واحد",two:"شهرين",many:"أشهر",single:"شهر"},year:{one:"سنة واحدة",two:"سنتين",many:"سنوات",single:"سنة"}},en:{second:{one:"one second",two:"two seconds",many:"seconds",single:"second"},minute:{one:"one minute",two:"two minutes",many:"minutes",single:"minute"},hour:{one:"one hour",two:"two hours",many:"hours",single:"hour"},day:{one:"one day",two:"two days",many:"days",single:"day"},month:{one:"one month",two:"two months",many:"months",single:"month"},year:{one:"one year",two:"two years",many:"years",single:"year"}}};const f=forms[lang][unit];if(value===1)return f.one;if(value===2)return f.two;if(lang==="ar"){if(value>=3&&value<=10)return`${value} ${f.many}`;return` ${value} ${f.single}`}else{return`${value}${value===1?f.single:f.many}`}}function formatAgo(seconds,lang){const formatted=formatTime(seconds,lang);return lang==="ar"?` منذ ${formatted}`:`${formatted} ago`}function formatTime(seconds,lang){for(const interval of[{label:"year",seconds:31536000},{label:"month",seconds:2592000},{label:"day",seconds:86400},{label:"hour",seconds:3600},{label:"minute",seconds:60},{label:"second",seconds:1}]){const count=Math.floor(seconds/interval.seconds);if(count>=1){return formatNumberWithUnit(count,interval.label,lang)}}return lang==="ar"?" لحظة ":"just now"}
 //

