function run_once_post() {
 if(facebook_timeline === true){
  const timeline = document.querySelector("#timeline");
     const facebook_url = document.querySelector("#facebook_url");
     if(timeline && facebook_url && facebook_url.href.startsWith("https://www.facebook.com/")){
      timeline.innerHTML = `<iframe src="https://www.facebook.com/plugins/page.php?href=${facebook_url}&tabs=timeline&width=300&height=500&show_facepile=false&hide_cover=true&hide_cta=true&lazy=true"
       width="300" height="500" scrolling="no" frameborder="0" allowfullscreen="true" allow="autoplay; clipboard-write; encrypted-media; picture-in-picture; web-share">
      </iframe>`;
    }
  }


}

// تنفيذ مرة واحدة فقط
function once_handler() {
    run_once_post();
    document.removeEventListener("mousemove", once_handler);
    document.removeEventListener("touchstart", once_handler);
}

document.addEventListener("mousemove", once_handler, { passive: true });
document.addEventListener("touchstart", once_handler, { passive: true });


